// Anchored regex enforcing the contract documented on validateEmail:
//   - local part: one or more chars from [A-Za-z0-9._%+-]
//   - single literal '@' (no other '@' can appear because neither character
//     class contains it and the pattern is anchored end-to-end)
//   - one or more domain labels each matching [A-Za-z0-9] or
//     [A-Za-z0-9][A-Za-z0-9-]*[A-Za-z0-9] followed by '.', which forbids
//     leading or trailing hyphens in any label and guarantees >=1 dot
//   - TLD of two or more ASCII letters
// Because no part of the pattern matches whitespace and ^/$ anchor the
// whole string, any whitespace character causes the match to fail.
const EMAIL_RE = /^[A-Za-z0-9._%+-]+@(?:[A-Za-z0-9](?:[A-Za-z0-9-]*[A-Za-z0-9])?\.)+[A-Za-z]{2,}$/;

/**
 * Returns true if `email` is a syntactically valid email address per the
 * basic local@domain.tld grammar described above, false otherwise.
 *
 * Non-string input, empty strings, and any input containing whitespace
 * all return false.
 *
 * @param {unknown} email
 * @returns {boolean}
 */
export function validateEmail(email) {
    if (typeof email !== "string" || email.length === 0) {
        return false;
    }
    return EMAIL_RE.test(email);
}

