import { describe, it, expect } from "vitest";
import { normalize, validateEmail } from "./validate.js";

describe("normalize", () => {
    it("trims and lowercases string input", () => {
        expect(normalize("  Foo  ")).toBe("foo");
    });
    it("returns empty string for non-string input", () => {
        expect(normalize(null)).toBe("");
        expect(normalize(undefined)).toBe("");
        expect(normalize(42)).toBe("");
    });
});

// Tests added in iteration 2 in response to the rubric grader's C2 finding
// on claude-workflow-plugin-5cu. Each case exercises a user-visible branch
// of the contract documented on validateEmail. We assert against the strict
// booleans `true` / `false` (not truthy / falsy) because the contract
// promises a strict boolean return.
describe("validateEmail", () => {
    it("returns true for a plain valid address", () => {
        expect(validateEmail("user@example.com")).toBe(true);
    });

    it("returns false for non-string input (null, undefined, number)", () => {
        expect(validateEmail(null)).toBe(false);
        expect(validateEmail(undefined)).toBe(false);
        expect(validateEmail(42)).toBe(false);
    });

    it("returns false for the empty string", () => {
        expect(validateEmail("")).toBe(false);
    });

    it("returns false for input containing whitespace", () => {
        // Leading, trailing, and embedded whitespace must all be rejected,
        // including whitespace adjacent to an otherwise-valid address.
        expect(validateEmail(" user@example.com")).toBe(false);
        expect(validateEmail("user@example.com ")).toBe(false);
        expect(validateEmail("user @example.com")).toBe(false);
        expect(validateEmail("user@ example.com")).toBe(false);
        expect(validateEmail("user\t@example.com")).toBe(false);
    });

    it("returns false for input with zero or multiple '@' characters", () => {
        expect(validateEmail("userexample.com")).toBe(false);
        expect(validateEmail("user@@example.com")).toBe(false);
        expect(validateEmail("user@host@example.com")).toBe(false);
    });

    it("returns false when the domain has no dot", () => {
        expect(validateEmail("user@example")).toBe(false);
        expect(validateEmail("user@localhost")).toBe(false);
    });

    it("returns false when the TLD is shorter than 2 letters", () => {
        expect(validateEmail("user@example.c")).toBe(false);
        expect(validateEmail("user@example.")).toBe(false);
    });

    it("returns false for a domain label with a leading or trailing hyphen", () => {
        expect(validateEmail("user@-example.com")).toBe(false);
        expect(validateEmail("user@example-.com")).toBe(false);
        expect(validateEmail("user@foo.-bar.com")).toBe(false);
        expect(validateEmail("user@foo.bar-.com")).toBe(false);
    });
});

